                <div title={`${fmt(m.booked)} booked`} style={{ width: 12, height: `${(m.booked / maxMonthBooked) * 100}%`, background: "#10b981", borderRadius: "2px 2px 0 0", minHeight: m.booked > 0 ? 3 : 0 }}></div>
